select distinct top 50 u.id, u.name, count(o.id) as order_count, coalesce(sum(o.total),0) total from public.users u inner join orders o on o.user_id = u.id left join (select id, name from regions where active = true) r on r.id = u.region_id where (u.created_at >= '2024-01-01' and u.status in ('active','trial')) or u.is_admin = true group by u.id, u.name having count(o.id) > 3 order by order_count desc, u.name asc limit 100 offset 20;
